#!/usr/bin/env python3
"""Pillar 92 (Part CXCII): Tomotope symmetry structure summary

This script collects the various structural facts about the tomotope
monodromy group \(\Gamma\) and its associated automorphism set \(H\cong P_0\).
By this stage we have:

  * \(|\Gamma|=18\,432\); generated by involutions r0, r1, r2, r3.
  * \(|H|=96\); an external group of colour‑preserving automorphisms.
  * Every element of \(\Gamma\) commutes with every element of \(H\).
  * The intersection \(\Gamma\cap H\) consists only of the identity.
  * There is no nontrivial normal subgroup of \(\Gamma\) of order 192
    (N is not normal); conjugacy classes were enumerated in Pillar 91.

Together, these facts imply that the combined subgroup of \(S_{192}\) generated
by \(\Gamma\) and \(H\) is the **direct product**
\(\Gamma\times H\) of order 1 769 472.  The regular subgroup \(N\) from
Pillar 85 provides a transitive action on the 192 flags but is not normal in
\(\Gamma\); its structure will be studied separately.

The summary written by this module records the numerical checks that underlie
these statements and produces a human‑readable report.
"""
from __future__ import annotations

import json
from collections import Counter
from pathlib import Path

from THEORY_PART_CXCVII_AUT_NORMALISER import load_permutations, build_gamma
from THEORY_PART_CXCVI_TOMOTOPE_AUTOMORPHISMS import (
    compute_automorphisms,
    build_graph,
    load_r_generators,
)

ROOT = Path(__file__).resolve().parent


def compose(p: tuple[int, ...], q: tuple[int, ...]) -> tuple[int, ...]:
    return tuple(p[q[i]] for i in range(len(p)))


def invert(p: tuple[int, ...]) -> tuple[int, ...]:
    inv = [0] * len(p)
    for i, j in enumerate(p):
        inv[j] = i
    return tuple(inv)


def analyze() -> dict:
    perms = load_permutations()
    Gamma = build_gamma(perms)
    autos = compute_automorphisms(build_graph(load_r_generators()))
    H = [tuple(autos[i][j] for j in range(192)) for i in range(len(autos))]

    # intersection size
    inter = sum(1 for h in H if h in set(Gamma))
    # commutativity test
    commute = all(compose(g, h) == compose(h, g) for g in Gamma for h in H)
    # closure size predicted by direct product
    product_order = len(Gamma) * len(H)
    # conjugacy class sizes of Gamma
    classes = []
    seen = set()
    for g in Gamma:
        if g in seen:
            continue
        cls = set()
        for h in Gamma:
            invh = invert(h)
            cls.add(compose(compose(h, g), invh))
        classes.append(cls)
        seen.update(cls)
    class_sizes = sorted(len(c) for c in classes)

    return {
        "Gamma_order": len(Gamma),
        "Aut_order": len(H),
        "Gamma_intersect_Aut": inter,
        "commute_with_Gamma": commute,
        "direct_product_order": product_order,
        "num_conj_classes": len(classes),
        "conj_class_sizes": class_sizes,
    }


def write_results(summary: dict):
    OUT_SUM = ROOT / "tomotope_structure_summary.json"
    OUT_REPORT = ROOT / "tomotope_structure_report.md"
    OUT_SUM.write_text(json.dumps(summary, indent=2))
    with open(OUT_REPORT, "w", encoding="utf-8") as f:
        f.write("# Tomotope Structure Report\n\n")
        f.write(json.dumps(summary, indent=2))


def main():
    summ = analyze()
    # sanity checks
    assert summ["Gamma_order"] == 18432
    assert summ["Aut_order"] == 96
    assert summ["Gamma_intersect_Aut"] == 1
    assert summ["commute_with_Gamma"]
    assert summ["direct_product_order"] == 18432 * 96
    write_results(summ)
    print("structure summary written")


if __name__ == "__main__":
    main()
